package com.agrios.platform.workmanagement.api;
import com.agrios.platform.common.web.TenantContextResolver; import com.agrios.platform.workmanagement.application.WorkManagementQueryService; import jakarta.servlet.http.HttpServletRequest; import java.time.Instant; import java.util.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/work-management") public class WorkManagementController {private final WorkManagementQueryService service;private final TenantContextResolver tenants;public WorkManagementController(WorkManagementQueryService s,TenantContextResolver t){service=s;tenants=t;}@GetMapping("/calendar") List<WorkManagementDtos.CalendarEntry> calendar(@RequestParam Instant from,@RequestParam Instant to,HttpServletRequest r){return service.calendar(tenants.resolve(r).tenantId(),from,to);}@GetMapping("/farms/{farmId}/dashboard") WorkManagementDtos.Dashboard dashboard(@PathVariable UUID farmId,@RequestParam(required=false) Instant at,HttpServletRequest r){return service.dashboard(tenants.resolve(r).tenantId(),farmId,at==null?Instant.now():at);}}
